:root { --bg: #f4f6f8; --panel: #ffffff; --primary: #5f8fb3; --primary-soft: #eaf2f7; --text: #6f7f8a; --muted: #9aa7b1; --border: #d9e1e6; --danger: #c97f7f; --success: #78a888; }* { box-sizing: border-box; }body { margin: 0px; font-family: "Segoe UI", Arial, sans-serif; background: var(--bg); color: var(--text); }.header { background: rgb(255, 255, 255); border-bottom: 1px solid var(--border); padding: 18px 24px; }.header h1 { margin: 0px; font-size: 20px; font-weight: 600; color: rgb(114, 134, 146); }.header p { margin: 6px 0px 0px; font-size: 13px; color: var(--muted); }.wrapper { max-width: 860px; margin: 28px auto; padding: 0px 20px 60px; }.card { background: var(--panel); border: 1px solid var(--border); border-radius: 10px; padding: 24px; box-shadow: rgba(0, 0, 0, 0.03) 0px 1px 2px; }.section + .section { margin-top: 26px; padding-top: 22px; border-top: 1px solid rgb(238, 242, 244); }.section h2 { margin: 0px 0px 6px; font-size: 16px; font-weight: 600; color: rgb(115, 134, 146); }.section p { margin: 0px 0px 16px; font-size: 12px; color: var(--muted); line-height: 1.5; }.grid { display: grid; grid-template-columns: repeat(2, minmax(0px, 1fr)); gap: 16px; }.field { display: flex; flex-direction: column; gap: 6px; }.field.full { grid-column: 1 / -1; }label { font-size: 12px; font-weight: 500; color: rgb(130, 147, 157); }.hint { font-size: 11px; color: rgb(167, 178, 185); line-height: 1.4; margin-top: 2px; }input, select, textarea { width: 100%; padding: 10px 12px; border: 1px solid var(--border); border-radius: 8px; font-size: 13px; color: rgb(113, 129, 140); background: rgb(252, 253, 254); outline: none; }input::placeholder, textarea::placeholder { color: rgb(181, 192, 199); }textarea { min-height: 90px; resize: vertical; }.inline-options { display: flex; flex-wrap: wrap; gap: 14px; margin-top: 4px; }.inline-options label { display: inline-flex; align-items: center; gap: 6px; font-size: 12px; font-weight: 400; color: rgb(133, 149, 159); cursor: pointer; }.inline-options input[type="radio"], .inline-options input[type="checkbox"] { width: 14px; height: 14px; margin: 0px; accent-color: rgb(138, 169, 191); }.tag-row { display: flex; flex-wrap: wrap; gap: 8px; }.tag { padding: 6px 10px; border-radius: 999px; font-size: 11px; background: var(--primary-soft); color: rgb(125, 150, 167); border: 1px solid rgb(217, 229, 237); cursor: pointer; user-select: none; }.tag.active { background: rgb(220, 234, 243); border-color: rgb(200, 220, 232); }.banner { margin-top: 18px; padding: 12px 14px; border-radius: 8px; background: rgb(250, 252, 253); border: 1px solid rgb(237, 242, 245); font-size: 12px; color: rgb(154, 168, 178); line-height: 1.5; }.status { margin-top: 18px; padding: 11px 14px; border-radius: 8px; font-size: 12px; background: rgb(251, 252, 253); border: 1px solid rgb(233, 238, 241); color: rgb(151, 165, 175); }.actions { display: flex; justify-content: space-between; align-items: center; gap: 12px; margin-top: 28px; flex-wrap: wrap; }.left-actions, .right-actions { display: flex; gap: 10px; flex-wrap: wrap; }button { border: 1px solid var(--border); background: white; color: rgb(125, 143, 154); border-radius: 8px; padding: 10px 14px; font-size: 13px; cursor: pointer; }.primary { background: var(--primary); color: rgb(234, 244, 250); border-color: rgb(95, 143, 179); }.linkish { font-size: 12px; color: rgb(140, 162, 177); text-decoration: underline; cursor: pointer; }.footer-note { margin-top: 22px; font-size: 11px; color: rgb(172, 182, 189); text-align: right; }.hidden-block { margin-top: 34px; padding: 18px; background: rgb(252, 252, 253); border: 1px dashed rgb(227, 234, 238); border-radius: 8px; }.hidden-block h3 { margin: 0px 0px 8px; font-size: 14px; color: rgb(127, 145, 156); }.hidden-block p { margin: 0px; font-size: 12px; color: rgb(156, 170, 179); line-height: 1.5; }@media (max-width: 720px) {
  .grid { grid-template-columns: 1fr; }
  .actions { flex-direction: column; align-items: stretch; }
  .left-actions, .right-actions { width: 100%; justify-content: space-between; }
}
